data.content:
**MSTest 3.x+ does have comparison assertions.** Here's what's available:

```csharp
Assert.IsGreaterThan(lowerBound, actual);
Assert.IsLessThan(upperBound, actual);
Assert.IsInRange(actual, low, high);
```

For your `ScoreCalculator`, here's how to apply them for boundary testing:

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    public void CalculatePercentage_AllCorrect_Returns100()
    {
        var result = _calc.CalculatePercentage(10, 10);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_ReturnsValueInRange()
    {
        var result = _calc.CalculatePercentage(7, 10);
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.AreEqual(70.0, result);
    }

    [TestMethod]
    public void NormalizeScore_BelowMax_ReturnsPercentageAboveZero()
    {
        var result = _calc.NormalizeScore(50, 200);
        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    [DataRow(90, "A")]
    [DataRow(80, "B")]
    [DataRow(70, "C")]
    [DataRow(60, "D")]
    [DataRow(59, "F")]
    public void GetGrade_AtBoundary_ReturnsExpectedGrade(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }
}
```

**Key points:**
- `Assert.IsInRange(actual, low, high)` — confirms a value is within bounds
- `Assert.IsGreaterThan(lowerBound, actual)` — confirms actual > lowerBound
- `Assert.IsLessThan(upperBound, actual)` — confirms actual < upperBound

These require **MSTest 3.x+** (the `MSTest` metapackage or `MSTest.Sdk`). They produce much better failure messages than `Assert.IsTrue(value > 0)`.
